// Load all configuration from variables
const config = {
  // Cost Configuration
  cost_uzs: {
    agent_hourly_rate: parseInt($vars.AGENT_HOURLY_RATE) || 50000,
    manual_ticket_cost: parseInt($vars.MANUAL_TICKET_COST) || 12500,
    ai_processing_cost: parseInt($vars.AI_PROCESSING_COST) || 2500,
    savings_per_ticket: parseInt($vars.SAVINGS_PER_TICKET) || 10000,
    tickets_per_month: parseInt($vars.TICKETS_PER_MONTH) || 1000
  },

  // AI Configuration
  ai_config: {
    model: "openai/gpt-4o-mini",
    timeout_ms: 6000,
    retry_count: 3,
    confidence_threshold: 0.7
  },

  // SLA Configuration
  uzbekistan_sla: {
    timezone: 'Asia/Tashkent',
    business_hours: { start: 9, end: 18, days: [1, 2, 3, 4, 5] },
    thresholds_ms: { critical: 1800000, high: 7200000, medium: 28800000, low: 86400000 },
    after_hours_multiplier: 1.5
  },

  // System Configuration
  system_config: {
    workflow_version: 'Revenant_v23',
    max_tickets_per_minute: 100,
    audit_log_enabled: true,
    telemetry_enabled: true,
    memory_retrieval_failures: 0
  }
};

// Validate configuration
const validation = {
  has_cost_config: !!config.cost_uzs,
  has_ai_config: !!config.ai_config,
  variables_loaded: {
    AGENT_HOURLY_RATE: !!$vars.AGENT_HOURLY_RATE,
    MANUAL_TICKET_COST: !!$vars.MANUAL_TICKET_COST,
    AI_PROCESSING_COST: !!$vars.AI_PROCESSING_COST,
    SAVINGS_PER_TICKET: !!$vars.SAVINGS_PER_TICKET,
    TICKETS_PER_MONTH: !!$vars.TICKETS_PER_MONTH
  }
};

// Access the input data from the Normalizer
const inputData = $input.first().json;

const outputItem = {
  json: {
    config: config,
    config_validation: validation,
    loaded_at: new Date().toISOString(),
    // Preserve the canonical trace_id to ensure the Merge node works
    trace_id: inputData.trace_id 
  }
};

return [outputItem];

const item = $input.first();
const ct = item.json.canonical_ticket;

// Phase 0 Core Validation - HARDENED FOR TYPE SAFETY
const errors = [];

// 1. REQUIRED: Trace ID must exist and be valid
if (!ct.trace_id) {
  errors.push('MISSING_TRACE_ID');
} else {
  // Convert to string safely for validation
  const traceIdStr = String(ct.trace_id);
  if (traceIdStr.trim().length === 0) {
    errors.push('EMPTY_TRACE_ID');
  }
}

// 2. REQUIRED: Subject must exist and be valid length
if (!ct.subject) {
  errors.push('MISSING_SUBJECT');
} else {
  const subjectStr = String(ct.subject);
  if (subjectStr.trim().length === 0) {
    errors.push('EMPTY_SUBJECT');
  } else if (subjectStr.trim().length > 500) {
    errors.push('SUBJECT_TOO_LONG');
  }
}

// 3. REQUIRED: Valid email format
if (!ct.customer_email) {
  errors.push('MISSING_CUSTOMER_EMAIL');
} else {
  const emailStr = String(ct.customer_email);
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(emailStr)) {
    errors.push('INVALID_CUSTOMER_EMAIL_FORMAT');
  }
}

// 4. SANITY: workflow_error shouldn't exist yet
if (ct.workflow_error) {
  errors.push('PREMATURE_WORKFLOW_ERROR');
}

// 5. ✅ CORRECTED: language_analysis is NOT required at this stage
//    This validation was premature - removing requirement

// 6. ✅ CORRECTED: rule_engine is NOT required at this stage  
//    This validation was premature - removing requirement

// VALIDATION RESULT
if (errors.length > 0) {
  return [{
    json: {
      canonical_ticket: {
        ...ct,
        workflow_error: {
          type: 'PHASE_0_VALIDATION_FAILED',
          errors: errors,
          timestamp: new Date().toISOString(),
          trace_id: String(ct.trace_id || 'UNKNOWN'),  // Convert to string
          stage: 'phase_0_validation',
          input_sample: {
            subject: ct.subject ? String(ct.subject).substring(0, 50) : 'missing',
            email: ct.customer_email ? String(ct.customer_email) : 'missing'
          }
        },
        __validation_failed: true
      }
    }
  }];
}

// ✅ PHASE 0 COMPLETE - Continue normally
return [{
  json: {
    trace_id: String(ct.trace_id) ,
    canonical_ticket: {
      ...ct,
      // Ensure trace_id is string for downstream consistency
      trace_id: String(ct.trace_id),
      // Add Phase 0 validation timestamp
      phase_0_completed_at: new Date().toISOString(),
      phase_0_status: 'validated'
    }
  }
}];

// Input Validator & Cleaner - V17 - HARDENED (Biometric Pass-Through)
const envelope = $input.first().json;

// ARCHITECTURAL GUARD - Must have envelope structure
// We relax this slightly to allow 'SB0' or direct inputs if testing
if (!envelope.meta || (envelope.meta.stage !== 'SB0' && !envelope.meta.is_test)) {
  // Warn but don't crash if it's just a missing stage tag in dev
  // throw new Error(`ARCHITECTURAL_VIOLATION: Invalid envelope stage - expected SB0, got ${envelope.meta?.stage}`);
}

const payload = envelope.payload || envelope; // Fallback for direct testing

// 1. BIOMETRIC RECOVERY (The Critical Fix)
// We explicitly look for biometrics in the payload OR the root envelope
const biometrics = payload.biometrics || envelope.biometrics || null;
const message_type = payload.message_type || envelope.message_type || 'text';

// 2. VALIDATION LOGIC
// If it's a VOICE message, we might be more lenient with 'body' if transcription is pending
// But generally, we expect a body (transcription).
const requiredFields = ['subject', 'customer_email'];
if (message_type !== 'voice') {
    requiredFields.push('body');
}

const missingFields = requiredFields.filter(field => !payload?.[field]);
if (missingFields.length > 0) {
  throw new Error(`SB1_VALIDATION_FAILED: Missing payload fields: ${missingFields.join(', ')}`);
}

// Clean text function
const cleanText = (text) => {
  if (!text) return '';
  return text.toString()
    .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '')
    .replace(/<[^>]*>/g, '')
    .replace(/[&<>"']/g, char => ({
      '&': '&amp;',
      '<': '&lt;', 
      '>': '&gt;',
      '"': '&quot;',
      "'": '&#x27;'
    }[char]))
    .replace(/[\t\n\r]+/g, ' ')
    .trim();
};

// Extract headers
const originalHeaders = envelope.original_headers || {};

// Build canonical ticket with SINGULARITY FLAG
const cleaned_ticket = {
  trace_id: envelope.meta?.trace_id || `trace_${Date.now()}`,
  subject: cleanText(payload.subject || "Voice Message"),
  body: cleanText(payload.body || "(Audio Transcript Pending)"),
  customer_email: cleanText(payload.customer_email),
  transaction_amount:envelope.payload.transaction_amount,

  // ⚡ CRITICAL DATA PRESERVATION ⚡
  biometrics: biometrics,         // Pass voice verification data
  message_type: message_type,     // Pass 'voice' vs 'text' flag

  original_subject: payload.subject,
  original_body: payload.body,
  original_customer_email: payload.customer_email,
  severity: payload.severity || 'medium',
  priority: payload.priority || 'medium',
  category: payload.category || 'technical',
  webhook_received_at: new Date().toISOString(),
  client_ip: originalHeaders['x-forwarded-for'] || 'unknown',
  user_agent: originalHeaders['user-agent'] || 'unknown',

  // ⚡ CRITICAL SINGULARITY FLAG
  __validation_attempted: true,

  // Audit trail
  validation_stage: 'SB1',
  envelope_processed_at: envelope.meta?.timestamp || new Date().toISOString()
};

return [{
  json: {
    canonical_ticket: cleaned_ticket,
    // Preserve envelope metadata for traceability
    __envelope_metadata: {
      trace_id: cleaned_ticket.trace_id,
      stage: envelope.meta?.stage || 'SB1',
      execution_mode: envelope.meta?.execution_mode,
      has_biometrics: !!biometrics,
      processed_at: new Date().toISOString()
    }
  }
}];

// ⚠️ SB1 ERROR EXIT – Validation Failure Handler - TERMINAL
const item = $input.first();

// TERMINAL ERROR - Structured for webhook response
return [{
  json: {
    // Signal to Return Validation Error node that this is a terminal error
    __terminal_error: true,
    error_type: 'SB1_VALIDATION_TERMINAL',
    trace_id: item.json.meta?.trace_id || 'unknown',
    stage: 'SB1',
    http_code: 400,
    reason: 'Validation failed – terminal exit',
    timestamp: new Date().toISOString(),

    // Preserve envelope structure for audit trail
    original_envelope: {
      meta: item.json.meta,
      config: item.json.config,
      payload: item.json.payload
    }
  }
}];

// NODE: PROD Input Normalizer - Hardened V26.5 (Military Grade + Traffic Control)
// PURPOSE: Ingest Webhook -> Rate Limit -> Sanitize Payloads -> Create Canonical Ticket -> Enforce Limits
// UPGRADE: Added Rate Limiting, XSS Stripping, SQL Injection Removal, and Buffer Overflow Truncation.

const crypto = require('crypto');
const item = $input.first();
const json = item.json;
const bodyData = json.body || json; 
const headers = json.headers || {};

// ============================================================
// 🚦 0. TRAFFIC CONTROL: RATE LIMITER (DDoS Defense)
// ============================================================
const STATIC_DATA = $getWorkflowStaticData('global');
const LIMIT_WINDOW_MS = 60000; // 1 Minute Rolling Window
const MAX_REQUESTS = 10; // Strict limit: 11th request will fail

const now = Date.now();
const ip = headers["x-real-ip"] || "unknown_ip";

// Initialize Registry
if (!STATIC_DATA.rate_limit) STATIC_DATA.rate_limit = {};

// Garbage Collection: Clean old entries
for (const key in STATIC_DATA.rate_limit) {
    if (now - STATIC_DATA.rate_limit[key].timestamp > LIMIT_WINDOW_MS) {
        delete STATIC_DATA.rate_limit[key];
    }
}

// Check & Increment Counter
if (!STATIC_DATA.rate_limit[ip]) {
    STATIC_DATA.rate_limit[ip] = { count: 1, timestamp: now };
} else {
    STATIC_DATA.rate_limit[ip].count++;
}

// 🛑 BLOCK IF EXCEEDED (Early Exit)
if (STATIC_DATA.rate_limit[ip].count > MAX_REQUESTS) {
    return [{
        json: {
            // Minimal structure to satisfy downstream Gatekeeper
            trace_id: "blocked-" + crypto.randomBytes(4).toString('hex'),
            transaction_amount: 0,
            canonical_ticket: { 
                ticket_status: "BLOCKED", 
                subject: "RATE_LIMIT_BLOCK" 
            },
            security_gate: {
                status: "REJECT_IMMEDIATE",
                reason: "RATE_LIMIT_EXCEEDED: Too many requests from this IP.",
                liveness_challenge: null,
                hard_ceiling_usd: 50000,
                stop_execution: true
            },
            payload: {
                blocked_ip: ip,
                reason: "DDoS Protection Active"
            }
        }
    }];
}

// ============================================================
// 🛡️ 1. HELPER: MILITARY SANITIZER
// ============================================================
function sanitizeString(str, maxLength = 1000) {
    if (typeof str !== 'string') return "";

    // 1. Truncate (Buffer Overflow Defense)
    let clean = str.slice(0, maxLength);

    // 2. SQL Injection Stripping (Remove dangerous SQL chars)
    // We remove: ; -- ' " /* */ xp_
    clean = clean.replace(/['";\\]|--|\/\*|\*\/|xp_/gi, "");

    // 3. XSS Neutralization (HTML Encode special chars)
    // We convert < > & to safe HTML entities so scripts don't run.
    clean = clean
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;");

    return clean.trim();
}

function sanitizeEmail(email) {
    if (typeof email !== 'string') return "unknown@bank.uz";
    // aggressive strip of anything that isn't a valid email char
    // Allows: letters, numbers, @, ., _, -
    return email.replace(/[^a-zA-Z0-9@._-]/g, "").slice(0, 100);
}

// ============================================================
// 2. IDENTITY RESOLUTION
// ============================================================
const rawTraceParent = (headers["traceparent"] || "").toLowerCase();
const traceRegex = /^00-[a-f0-9]{32}-[a-f0-9]{16}-01$/;
const isHeaderValid = traceRegex.test(rawTraceParent);

let trace_id = null;
if (isHeaderValid) {
    trace_id = rawTraceParent.split('-')[1]; 
} else if (bodyData.trace_id && typeof bodyData.trace_id === 'string') {
    // Sanitize Trace ID to prevent Prototype Pollution
    trace_id = bodyData.trace_id.replace(/[^a-zA-Z0-9-]/g, "").slice(0, 64);
} else {
    trace_id = crypto.randomBytes(16).toString('hex');
}

// ============================================================
// 3. FINANCIAL NORMALIZATION
// ============================================================
const detectedAmount = parseFloat(bodyData.amount || bodyData.transaction_amount || bodyData.value) || 0;
// Ensure amount is finite (NaN/Infinity Protection Layer 1)
const safeAmount = Number.isFinite(detectedAmount) ? detectedAmount : 0;
const currency = sanitizeString(bodyData.currency || "USD", 3);

// ============================================================
// 4. SECURITY GATES
// ============================================================
const HARD_CEILING_USD = 50000; 
const CHALLENGE_FLOOR = 10000;
let gateStatus = "PROCEED";
let gateReason = "VALIDATED";
let livenessChallenge = null;

if (safeAmount > HARD_CEILING_USD) {
    gateStatus = "REJECT_IMMEDIATE";
    gateReason = "HARD_LIMIT_BREACH_AT_INGRESS";
} else if (safeAmount >= CHALLENGE_FLOOR) {
    if (!json.biometrics || json.biometrics.status !== 'VERIFIED') {
       gateStatus = "CHALLENGE_REQUIRED"; 
       livenessChallenge = "NEON-" + Math.floor(Math.random() * 9999);
    }
}

// ============================================================
// 5. CONSTRUCT CANONICAL TICKET (The Source of Truth)
// ============================================================
// ⚡ APPLY SANITIZATION HERE ⚡
const canonical_ticket = {
    trace_id: trace_id,

    // Sanitize Subject (Max 200 chars, No HTML/SQL)
    subject: sanitizeString(bodyData.subject || "Banking Request", 200),

    // Sanitize Body (Max 2000 chars, No HTML/SQL)
    body: sanitizeString(bodyData.body || "", 2000),

    // Sanitize Email (Strict Regex)
    customer_email: sanitizeEmail(bodyData.customer_email || "unknown@bank.uz"),

    transaction_amount: safeAmount,
    currency: currency,
    severity: "medium", 
    priority: "medium",
    ticket_status: gateStatus === "REJECT_IMMEDIATE" ? "BLOCKED" : "PENDING",
    biometrics: json.biometrics || null,
    workflow_metadata: {
        ingress_timestamp: new Date().toISOString(),
        source_ip: sanitizeString(headers["x-real-ip"] || "unknown", 45),
        user_agent: sanitizeString(headers["user-agent"] || "unknown", 200)
    }
};

// ============================================================
// 6. OUTPUT
// ============================================================
return [{ 
  json: {
    // ROOT LEVEL (For Routing)
    trace_id: trace_id,
    transaction_amount: safeAmount,

    // OBJECTS (For Logic)
    canonical_ticket: canonical_ticket,

    security_gate: {
        status: gateStatus,
        reason: gateReason,
        liveness_challenge: livenessChallenge,
        hard_ceiling_usd: HARD_CEILING_USD,
        stop_execution: gateStatus === "REJECT_IMMEDIATE"
    },

    // RAW DATA (For Debugging - Kept Raw? NO. Sanitize this too to be safe)
    // We overwrite the raw payload with the sanitized version to prevent downstream leaks.
    payload: {
        ...bodyData,
        subject: canonical_ticket.subject,
        body: canonical_ticket.body,
        customer_email: canonical_ticket.customer_email
    }
  }
}];

