const item = $input.first();
const ct = item.json.canonical_ticket;
const text = (ct.subject + ' ' + ct.body).toLowerCase();

// Priority Rules for Uzum Ecosystem
const rules = [
  { 
    intent: 'access_issue', 
    regex: /\b(403|401|login|password|access|denied|portal|kabinet|kirish|parol|vaxod|dostup|forbidden)\b/, 
    severity: 'high', 
    score: 0.95 
  },
  { 
    intent: 'payment_issue', 
    regex: /\b(payment|to'lov|oplat|o'tkazma|transak|card|karta|uzcard|humo|click|payme)\b/, 
    severity: 'critical', 
    score: 0.9 
  },
  { 
    intent: 'security_alert', 
    regex: /\b(security|xavfsizlik|hacker|attack|virus|hack|fishing|vzlom)\b/, 
    severity: 'critical', 
    score: 1.0 
  },
  { 
    intent: 'network_issue', 
    regex: /\b(internet|network|tarmoq|connect|sechenie|vpn|slow|sekin|medlenno)\b/, 
    severity: 'medium', 
    score: 0.85 
  }
];

let detectedIntent = 'general_inquiry';
let detectedSeverity = ct.severity || 'medium';
let ruleConfidence = 0.5;

for (const rule of rules) {
  if (rule.regex.test(text)) {
    detectedIntent = rule.intent;
    detectedSeverity = rule.severity;
    ruleConfidence = rule.score;
    // Boost severity if it's a Merchant specific issue
    if (text.includes('merchant') || text.includes('portal') || text.includes('tadbirkor')) {
        detectedSeverity = (detectedSeverity === 'critical') ? 'critical' : 'high';
    }
    break;
  }
}

return [{
  json: {
    ...item.json,
    canonical_ticket: {
      ...ct,
      rule_engine: {
        intent: detectedIntent,
        severity: detectedSeverity,
        confidence: ruleConfidence,
        detected_at: new Date().toISOString(),
        engine_version: "2.1.0-enterprise"
      },
      data_integrity: {
        ...ct.data_integrity,
        last_modified: Date.now(),
        modification_count: (ct.data_integrity?.modification_count || 0) + 1
      }
    }
  }
}];

/**
 * REVENANT ENTERPRISE: Rule-Based Severity Classifier V22
 * Logic: Multi-factor weighted heuristic engine.
 */
const item = $input.first();
const ct = item.json.canonical_ticket || item.json;
const text = (ct.subject + ' ' + ct.body).toLowerCase();
const features = ct.text_features || {};

// 1. Scoring Matrix (Enterprise Weights)
const scores = { critical: 0, high: 0, medium: 0, low: 0 };

const WEIGHTS = {
  CRITICAL_INDICATOR: 3.5,
  HIGH_INDICATOR: 2.0,
  ERROR_CODE_MATCH: 1.5,
  INTENT_ESCALATION: 2.5,
  LENGTH_PENALTY: 1.0
};

// 2. High-Fidelity Pattern Matching
const patterns = {
  critical: /\b(outage|down|breach|loss|emergency|ishlamayapti|отключен|критическая)\b/i,
  high: /\b(failed|cannot|unable|error|failed|urgent|tezda|сброс|ошибка)\b/i,
  technical_errors: /error\s+(403|500|502|503|401)|timeout|database/i
};

// 3. Execution Logic
if (patterns.critical.test(text)) scores.critical += WEIGHTS.CRITICAL_INDICATOR;
if (patterns.high.test(text)) scores.high += WEIGHTS.HIGH_INDICATOR;
if (patterns.technical_errors.test(text)) scores.high += WEIGHTS.ERROR_CODE_MATCH;

// Cross-reference Text Features
if (features.has_critical) scores.critical += 2;
if (features.has_error_code) scores.high += 1.5;

// 4. Intent-Aware Escalation (Cross-Node Intelligence)
if (ct.rule_engine?.intent === 'access_issue' && text.includes('merchant')) {
    scores.high += WEIGHTS.INTENT_ESCALATION;
}

// 5. Deterministic Severity Selection
const maxScore = Math.max(scores.critical, scores.high, scores.medium, scores.low);
let finalSeverity = 'medium';

if (scores.critical >= 3) finalSeverity = 'critical';
else if (scores.high >= 2) finalSeverity = 'high';
else if (scores.medium >= 1) finalSeverity = 'medium';
else finalSeverity = 'low';

const confidence = Math.min(0.98, 0.4 + (maxScore / 10));

return [{
  json: {
    ...item.json,
    rule_based_severity: {
      severity: finalSeverity,
      confidence: parseFloat(confidence.toFixed(2)),
      scores: scores,
      calculated_at: new Date().toISOString()
    },
    canonical_ticket: {
      ...ct,
      rule_based_severity: {
        severity: finalSeverity,
        confidence: parseFloat(confidence.toFixed(2)),
        scores: scores
      }
    }
  }
}];

// NODE: Text Feature Engineering - V26 (Hardened)
// CAPABILITY: Deterministic Intent & Entity Extraction
// CONSTITUTION: Law 1.2 (Enrichment) & Law 3 (Severity Logic)

const item = $input.first();
const inputData = item.json;
const ct = inputData.canonical_ticket || {};

// 1. TEXT PREPARATION
const text = (ct.subject + " " + ct.body).toLowerCase();

// 2. FEATURE EXTRACTION (REGEX - The "Eyes")
const features = {
    has_account_number: /\b\d{16,20}\b/.test(text),
    has_phone_number: /\+998\d{9}/.test(text),
    has_card_number: /\b8600\d{12}\b/.test(text),
    has_crypto_terms: /\b(crypto|bitcoin|usdt|binance)\b/.test(text),
    has_urgent_keywords: /\b(immediately|asap|urgent|tezda|fast)\b/.test(text),
    has_security_terms: /\b(hack|stolen|fraud|replay|attack)\b/.test(text)
};

// 3. DETERMINISTIC INTENT CLASSIFICATION
// We use a scoring matrix to determine the primary intent
const intents = {
    "FRAUD_REPORT": ["scam", "fraud", "hacked", "stolen", "o'girlangan", "firibgar"],
    "CARD_BLOCK": ["block", "freeze", "lost card", "yo'qolgan", "bloklash", "stop"],
    "TRANSFER_ISSUE": ["transfer", "sent", "money", "pul", "o'tkazma", "yetib bormadi", "pending"],
    "BALANCE_INQUIRY": ["balance", "balans", "qancha", "how much", "qolgan"],
    "SECURITY_ALERT": ["replay", "attack", "injection", "vulnerability", "test"]
};

let detectedIntent = "GENERAL_INQUIRY";
let maxScore = 0;

Object.entries(intents).forEach(([intent, keywords]) => {
    const matchCount = keywords.reduce((acc, kw) => acc + (text.includes(kw) ? 1 : 0), 0);
    if (matchCount > maxScore) {
        maxScore = matchCount;
        detectedIntent = intent;
    }
});

// 4. SEVERITY CALCULATION (Constitution Law 3)
// Severity = Function(Intent, Amount, Urgency)
let severity = "low";
const amount = ct.transaction_amount || inputData.transaction_amount || 0;

if (detectedIntent === "SECURITY_ALERT" || detectedIntent === "FRAUD_REPORT") {
    severity = "critical";
} else if (detectedIntent === "CARD_BLOCK") {
    severity = "high";
} else if (amount > 10000 || features.has_urgent_keywords) {
    severity = "high"; // High value or urgent requests are high priority
} else if (detectedIntent === "TRANSFER_ISSUE") {
    severity = "medium";
}

// 5. CONSTRUCT RULE ENGINE RESULT
const rule_engine = {
    intent: detectedIntent,
    confidence: maxScore > 0 ? 1.0 : 0.5, // Deterministic = 100% confidence if keyword found
    severity: severity,
    detected_at: new Date().toISOString(),
    engine_version: "2.1.0-hardened"
};

// 6. OUTPUT
return [{
    json: {
        ...inputData, // Preserve Trace ID & Amount

        // Enrich the Canonical Ticket
        canonical_ticket: {
            ...ct,
            text_features: features, // NOW POPULATED
            rule_engine: rule_engine,
            severity: severity, // Update Ticket Severity
            classification: {
                category: detectedIntent,
                source: "DETERMINISTIC_ENGINE_V26"
            }
        },

        // Expose for Switch Node
        rule_based_intent: detectedIntent,
        rule_based_severity: severity
    }
}];

/**
 * REVENANT ENTERPRISE: Pre-Fusion Normalizer V22
 * Logic: Conflict resolution & provenance stabilization.
 */
const item = $input.first();
const ct = item.json.canonical_ticket;

// 1. HARD VALIDATION: Fail-Fast for Data Integrity
if (!ct.rule_engine || !ct.rule_based_severity) {
  throw new Error(`INTEGRITY_VIOLATION: Missing intelligence inputs in trace ${ct.trace_id}`);
}

// 2. CONFLICT RESOLUTION (Expert Logic)
// If rule-based severity is 'critical' but engine says 'medium', we escalate to be safe.
const engineSev = ct.rule_engine.severity;
const ruleSev = ct.rule_based_severity.severity;

const SEVERITY_RANK = { critical: 4, high: 3, medium: 2, low: 1 };

const resolvedSeverity = (SEVERITY_RANK[ruleSev] >= SEVERITY_RANK[engineSev]) 
    ? ruleSev 
    : engineSev;

// 3. CONFIDENCE AGGREGATION
const normalizedConfidence = (ct.rule_engine.confidence + ct.rule_based_severity.confidence) / 2;

// 4. ENTERPRISE CLASSIFICATION OBJECT
const classification = {
  intent: ct.rule_engine.intent,
  severity: resolvedSeverity,
  confidence: parseFloat(normalizedConfidence.toFixed(2)),
  source: "hybrid_fusion_engine_v22",
  normalized_at: new Date().toISOString(),
  // EXPLAINABLE AI: Provenance maintains the "Why"
  provenance: {
    intent_source: "rule_engine_v21",
    severity_strategy: (ruleSev !== engineSev) ? "escalated_by_rule" : "consensus",
    raw_scores: {
      engine: engineSev,
      rules: ruleSev
    }
  }
};

// 5. IMMUTABLE UPDATE
return [{
  json: {
    canonical_ticket: {
      ...ct,
      classification: classification,
      data_integrity: {
        ...ct.data_integrity,
        last_modified: Date.now(),
        modification_count: (ct.data_integrity?.modification_count || 0) + 1,
        classification_normalized: true
      }
    }
  }
}];

