  // Strict Header Validation
  if (!/^[a-zA-Z0-9+/=]+$/.test(signature)) return { json: { ...input, failure_code: 'INVALID_SIG_ENCODING' } };

  // USE RAW HTTP BODY FROM PREVIOUS STEP
  const rawString = input.raw_response_body || "";

  const verifier = crypto.createVerify('SHA256');
