  if (!verifier.verify(pubKey, signature, 'base64')) {
    return { json: { ...input, failure_code: 'INVALID_JURISDICTION_SIG' } };
  }

  // HASH RAW BYTES
  const response_hash = crypto.createHash('sha256').update(rawString).digest('hex');

  return { json: { ...input, response_hash, failure_code: null } };
} catch (e) {
  return { json: { ...input, failure_code: 'SIG_EXCEPTION' } };
}

// Strict Global Deadline Enforcement
