return { json: { ...items[0].json, ...parsedBody, failure_code: failure_code, error: error, raw_response_body: raw_response_body } };

// BLOCK 7.6: DETERMINISTIC FORENSIC SIGNER (v27)
// CAPABILITY: Byte-Perfect Canonicalization + Dynamic Key Usage
const crypto = require('crypto');

// 1. GET DYNAMIC KEY (No more ENV vars)
const keyData = items[0].json;
const ROOT_SECRET = keyData.secret_key  ;
const KID = keyData.kid;

if (!ROOT_SECRET) {
    throw new Error("CRITICAL_SECURITY_FAIL: No active signing key found in registry.");
}

// 2. INGEST STATE DATA
// (Adjust references if your upstream node names differ slightly)
const trace = $("BLOCK 7.1: Trace Context Initializer").first().json.governance;
const scrubbedData = $("BLOCK 7.4: PII Forensic Scrubber").first().json.scrubbed_data;

// 3. DETERMINISTIC CANONICALIZATION (Tier-1 Requirement)
// Ensures {a:1, b:2} produces same hash as {b:2, a:1}
function canonicalize(obj, depth = 0) {
  if (depth > 5) throw new Error("JSON_DEPTH_EXCEEDED");
  if (obj === undefined || obj === null) return obj;
  if (typeof obj !== 'object') return obj;

  if (Array.isArray(obj)) {
    return obj.map(v => canonicalize(v, depth + 1));
  }

  return Object.keys(obj).sort().reduce((result, key) => {
    result[key] = canonicalize(obj[key], depth + 1);
    return result;
  }, {});
}

// 4. CONSTRUCT IMMUTABLE MANIFEST
const logManifest = {
  trace_id: trace.trace_id,
  kid: KID, // Key ID used for this signature
  timestamp: new Date().toISOString(),
  payload: canonicalize(scrubbedData)
};

// 5. SIGNING
const manifestString = JSON.stringify(logManifest);
const signature = crypto
  .createHmac('sha256', ROOT_SECRET)
  .update(manifestString)
  .digest('hex');

// 6. RETURN PROOF
return {
  json: {
    forensic_manifest: logManifest,
    integrity_proof: {
      signature: signature,
      kid: KID,
      alg: "HMAC-SHA256"
    },
    audit_ready: true
  }
};

// BLOCK 12.0: CBU REPORT GENERATOR (XML v2.1)
// COMPLIANCE: LRU-1115 Auto-Reporting

const tx = items[0].json;
const date = new Date().toISOString().split('T')[0];
const time = new Date().toISOString().split('T')[1].replace('Z', '');

// 1. CBU Standard XML Template
const xmlReport = `
<CBU_REPORT type="SAR" priority="HIGH">
  <HEADER>
    <BANK_ID>REV_FIN_01</BANK_ID>
    <REPORT_ID>${tx.trace_id}</REPORT_ID>
    <DATE>${date}</DATE>
    <TIME>${time}</TIME>
  </HEADER>
  <TRANSACTION>
    <ID>${tx.treaty_id}</ID>
    <AMOUNT currency="UZS">${tx.amount || 0}</AMOUNT>
    <STATUS>${tx.status}</STATUS>
    <INTEGRITY_HASH>${tx.response_hash}</INTEGRITY_HASH>
  </TRANSACTION>
  <RISK_ASSESSMENT>
    <SCORE>0</SCORE>
    <FLAGS>NONE</FLAGS>
  </RISK_ASSESSMENT>
</CBU_REPORT>`;

return {
  json: {
    report_file_name: `SAR_${date}_${tx.treaty_id}.xml`,
    xml_content: xmlReport,
    ...tx
  }
};

