/* BLOCK 7.5: ZERO-TRUST KEY FETCH (Tier-1) */
/* Replaces hardcoded ENV vars with dynamic key rotation */
SELECT kid, secret_key 
FROM ai_key_registry 
WHERE active = true 
  AND expires_at > NOW() 
ORDER BY created_at DESC 
LIMIT 1;
